Here's a complete example. I'll use a weather API as the REST wrapper to keep it concrete.

---

### Tool Class — `WeatherTools.cs`

```csharp
using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerToolType]
public class WeatherTools(HttpClient httpClient, ILogger<WeatherTools> logger)
{
    private const string BaseUrl = "https://api.open-meteo.com/v1";

    [McpServerTool, Description("Get the current weather for a location by latitude and longitude.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location (e.g. 47.6)")] double latitude,
        [Description("Longitude of the location (e.g. -122.3)")] double longitude,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching weather for ({Lat}, {Lon})", latitude, longitude);

        var url = $"{BaseUrl}/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m&temperature_unit=fahrenheit";

        var response = await httpClient.GetStringAsync(url, cancellationToken);

        using var doc = JsonDocument.Parse(response);
        var current = doc.RootElement.GetProperty("current");

        return $"Temperature: {current.GetProperty("temperature_2m")}°F, "
             + $"Wind: {current.GetProperty("wind_speed_10m")} mph";
    }

    [McpServerTool, Description("Get a multi-day weather forecast for a location.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        [Description("Number of forecast days (1-7)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        days = Math.Clamp(days, 1, 7);

        var url = $"{BaseUrl}/forecast?latitude={latitude}&longitude={longitude}"
                + $"&daily=temperature_2m_max,temperature_2m_min&temperature_unit=fahrenheit"
                + $"&forecast_days={days}";

        var response = await httpClient.GetStringAsync(url, cancellationToken);
        return response;
    }
}
```

### `Program.cs` — stdio transport

```csharp
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

var builder = Host.CreateApplicationBuilder(args);

// CRITICAL: log to stderr only — stdout is the JSON-RPC transport
builder.Logging.AddConsole(options =>
    options.LogToStandardErrorThreshold = LogLevel.Trace);

builder.Services.AddHttpClient();  // registers IHttpClientFactory + HttpClient

builder.Services.AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();      // discovers all [McpServerToolType] classes

await builder.Build().RunAsync();
```

---

### How DI works for MCP tools

The SDK has **two injection styles**, both automatic:

| Style | Class type | How services arrive |
|-------|-----------|---------------------|
| **Constructor injection** | Non-static class | Services in the constructor (e.g. `HttpClient`, `ILogger<T>`) |
| **Method parameter injection** | Static class | Services as method params alongside tool params |

**Key rule:** The SDK distinguishes tool parameters from DI services by type. Types registered in the DI container (like `HttpClient`, `ILogger<T>`, `IMcpServer`, `CancellationToken`) are **injected automatically and hidden** from the tool's JSON schema. Only parameters with `[Description]` are exposed to the LLM.

In the example above, `WeatherTools` uses **constructor injection** — `HttpClient` and `ILogger<WeatherTools>` are injected when the class is instantiated. The LLM only sees `latitude`, `longitude`, and `days`.

The static equivalent would be:

```csharp
[McpServerToolType]
public static class WeatherTools
{
    [McpServerTool, Description("Get current weather.")]
    public static async Task<string> GetCurrentWeather(
        [Description("Latitude")] double latitude,
        [Description("Longitude")] double longitude,
        HttpClient httpClient,          // ← injected, hidden from schema
        ILogger<object> logger,         // ← injected, hidden from schema
        CancellationToken ct = default) // ← injected, hidden from schema
    { ... }
}
```

**Constructor injection** (non-static) is preferred when tools share services or state across methods — it avoids repeating service params on every method signature.
